import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import '../../styles/storekeeper/storekeeper-dashboard.css';
import api from '../../services/api';

const StorekeeperDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      // Fetch inventory balance
      const balanceRes = await api.get('/inventory/balance');
      const summaryRes = await api.get('/inventory/summary');
      const lowStockRes = await api.get('/inventory/alerts/low-stock');

      setDashboard({
        balance: balanceRes.data?.data || [],
        summary: summaryRes.data?.data || {},
        lowStock: lowStockRes.data?.data || [],
      });
      setError(null);
    } catch (err) {
      console.error('Lỗi khi tải dữ liệu:', err);
      setError('Không thể tải dữ liệu dashboard. Vui lòng thử lại.');
    } finally {
      setLoading(false);
    }
  };

  const calculateTotalValue = () => {
    if (!dashboard?.balance) return 0;
    return dashboard.balance.reduce((sum, item) => sum + (item.total_value || 0), 0);
  };

  const calculateTotalItems = () => {
    if (!dashboard?.balance) return 0;
    return dashboard.balance.reduce((sum, item) => sum + (item.current_balance || 0), 0);
  };

  const getStockStatusBadge = (status) => {
    switch (status) {
      case 'LOW_STOCK':
        return <span className="storekeeper-dashboard__badge storekeeper-dashboard__badge--low">⚠️ Tồn kho thấp</span>;
      case 'OVER_STOCK':
        return <span className="storekeeper-dashboard__badge storekeeper-dashboard__badge--over">⚠️ Tồn kho cao</span>;
      default:
        return <span className="storekeeper-dashboard__badge storekeeper-dashboard__badge--normal">✓ Bình thường</span>;
    }
  };

  return (
    <div className="storekeeper-dashboard">
      <Header />
      <div className="storekeeper-dashboard__container">
        <Sidebar />
        <main className="storekeeper-dashboard__content">
          <div className="storekeeper-dashboard__header">
            <h1>Bảng điều khiển kho hàng</h1>
            <p>Quản lý tồn kho và giao dịch xuất nhập</p>
          </div>

          {error && (
            <div className="storekeeper-dashboard__error">
              <p>{error}</p>
              <button onClick={fetchDashboardData}>Thử lại</button>
            </div>
          )}

          {loading ? (
            <div className="storekeeper-dashboard__loading">
              <p>Đang tải dữ liệu...</p>
            </div>
          ) : (
            <>
              {/* Statistics Cards */}
              <div className="storekeeper-dashboard__stats">
                <div className="storekeeper-dashboard__stat-card">
                  <div className="stat-card__header">
                    <h3>Tổng giá trị kho</h3>
                    <span className="stat-card__icon">💰</span>
                  </div>
                  <div className="stat-card__value">
                    {calculateTotalValue().toLocaleString('vi-VN')} VNĐ
                  </div>
                  <p className="stat-card__label">Giá trị hiện tại</p>
                </div>

                <div className="storekeeper-dashboard__stat-card">
                  <div className="stat-card__header">
                    <h3>Số loại hàng</h3>
                    <span className="stat-card__icon">📦</span>
                  </div>
                  <div className="stat-card__value">
                    {dashboard?.balance?.length || 0}
                  </div>
                  <p className="stat-card__label">Mặt hàng trong kho</p>
                </div>

                <div className="storekeeper-dashboard__stat-card">
                  <div className="stat-card__header">
                    <h3>Cảnh báo tồn kho</h3>
                    <span className="stat-card__icon">⚠️</span>
                  </div>
                  <div className="stat-card__value" style={{ color: '#ef4444' }}>
                    {dashboard?.lowStock?.length || 0}
                  </div>
                  <p className="stat-card__label">Sản phẩm cần nhập</p>
                </div>

                <div className="storekeeper-dashboard__stat-card">
                  <div className="stat-card__header">
                    <h3>Danh mục</h3>
                    <span className="stat-card__icon">🏷️</span>
                  </div>
                  <div className="stat-card__value">
                    {dashboard?.summary?.total_categories || 0}
                  </div>
                  <p className="stat-card__label">Hạng mục sản phẩm</p>
                </div>
              </div>

              {/* Low Stock Alerts */}
              {dashboard?.lowStock && dashboard.lowStock.length > 0 && (
                <section className="storekeeper-dashboard__section">
                  <div className="storekeeper-dashboard__section-header">
                    <h2>⚠️ Sản phẩm tồn kho thấp</h2>
                    <Link to="/storekeeper/alerts" className="storekeeper-dashboard__link">
                      Xem tất cả →
                    </Link>
                  </div>
                  <table className="storekeeper-dashboard__table">
                    <thead>
                      <tr>
                        <th>Mã sản phẩm</th>
                        <th>Tên sản phẩm</th>
                        <th>Danh mục</th>
                        <th>Tồn kho hiện tại</th>
                        <th>Tối thiểu</th>
                        <th>Đơn vị</th>
                      </tr>
                    </thead>
                    <tbody>
                      {dashboard.lowStock.slice(0, 5).map((item) => (
                        <tr key={item.item_id}>
                          <td className="storekeeper-dashboard__code">{item.item_code}</td>
                          <td>{item.item_name}</td>
                          <td>{item.category_name}</td>
                          <td className="storekeeper-dashboard__quantity" style={{ color: '#ef4444' }}>
                            <strong>{parseFloat(item.current_balance).toFixed(2)}</strong>
                          </td>
                          <td>{parseFloat(item.min_quantity).toFixed(2)}</td>
                          <td>{item.unit}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </section>
              )}

              {/* All Inventory Items */}
              <section className="storekeeper-dashboard__section">
                <div className="storekeeper-dashboard__section-header">
                  <h2>📊 Danh sách tồn kho</h2>
                  <Link to="/storekeeper/inventory" className="storekeeper-dashboard__link">
                    Quản lý kho →
                  </Link>
                </div>
                <table className="storekeeper-dashboard__table">
                  <thead>
                    <tr>
                      <th>Mã sản phẩm</th>
                      <th>Tên sản phẩm</th>
                      <th>Danh mục</th>
                      <th>Tồn kho</th>
                      <th>Đơn giá</th>
                      <th>Tổng giá trị</th>
                      <th>Trạng thái</th>
                    </tr>
                  </thead>
                  <tbody>
                    {dashboard?.balance && dashboard.balance.length > 0 ? (
                      dashboard.balance.slice(0, 10).map((item) => (
                        <tr key={item.item_id}>
                          <td className="storekeeper-dashboard__code">{item.item_code}</td>
                          <td>{item.item_name}</td>
                          <td>{item.category_name}</td>
                          <td className="storekeeper-dashboard__quantity">
                            {parseFloat(item.current_balance).toFixed(2)} {item.unit}
                          </td>
                          <td>{parseFloat(item.unit_price).toLocaleString('vi-VN')} VNĐ</td>
                          <td>{parseFloat(item.total_value || 0).toLocaleString('vi-VN')} VNĐ</td>
                          <td>{getStockStatusBadge(item.stock_status)}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="7" className="storekeeper-dashboard__empty">
                          Chưa có dữ liệu
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </section>

              {/* Action Buttons */}
              <div className="storekeeper-dashboard__actions">
                <Link to="/storekeeper/inventory" className="storekeeper-dashboard__button storekeeper-dashboard__button--primary">
                  📦 Quản lý sản phẩm
                </Link>
                <Link to="/storekeeper/transactions" className="storekeeper-dashboard__button storekeeper-dashboard__button--secondary">
                  🔄 Giao dịch xuất/nhập
                </Link>
                <Link to="/storekeeper/alerts" className="storekeeper-dashboard__button storekeeper-dashboard__button--warning">
                  ⚠️ Cảnh báo tồn kho
                </Link>
              </div>
            </>
          )}
        </main>
      </div>
    </div>
  );
};

export default StorekeeperDashboard;
